Here's a comprehensive Jest test suite for the `formatCurrency` function:

```javascript
// formatCurrency.test.js

describe('formatCurrency', () => {
  // Mock implementation for testing
  const formatCurrency = (cents, currency) => {
    // List of supported currencies
    const supportedCurrencies = ['USD', 'EUR', 'GBP', 'JPY'];

    if (!supportedCurrencies.includes(currency)) {
      throw new Error(`Unsupported currency code: ${currency}`);
    }

    // Handle the conversion from cents to currency units
    const amount = cents / 100;

    // Currency symbols map
    const currencySymbols = {
      USD: '$',
      EUR: '€',
      GBP: '£',
      JPY: '¥'
    };

    const symbol = currencySymbols[currency];

    // Format the number with proper decimal places
    // JPY typically doesn't use decimal places
    const formattedAmount = currency === 'JPY' 
      ? Math.round(amount).toString()
      : amount.toFixed(2);

    // Handle negative values
    if (cents < 0) {
      return `-${symbol}${Math.abs(parseFloat(formattedAmount))}`;
    }

    return `${symbol}${formattedAmount}`;
  };

  test('should format zero cents correctly', () => {
    expect(formatCurrency(0, 'USD')).toBe('$0.00');
    expect(formatCurrency(0, 'EUR')).toBe('€0.00');
  });

  test('should handle negative values', () => {
    expect(formatCurrency(-1999, 'USD')).toBe('-$19.99');
    expect(formatCurrency(-500, 'EUR')).toBe('-€5.00');
    expect(formatCurrency(-12345, 'GBP')).toBe('-£123.45');
  });

  test('should handle values over 1 billion cents', () => {
    expect(formatCurrency(1000000000, 'USD')).toBe('$10000000.00');
    expect(formatCurrency(9999999999, 'USD')).toBe('$99999999.99');
    expect(formatCurrency(1234567890, 'EUR')).toBe('€12345678.90');
  });

  test('should throw error for unsupported currency codes', () => {
    expect(() => formatCurrency(100, 'XYZ')).toThrow('Unsupported currency code: XYZ');
    expect(() => formatCurrency(100, 'CAD')).toThrow('Unsupported currency code: CAD');
    expect(() => formatCurrency(100, '')).toThrow('Unsupported currency code: ');
    expect(() => formatCurrency(100, null)).toThrow();
  });

  test('should handle floating-point precision correctly', () => {
    expect(formatCurrency(1999, 'USD')).toBe('$19.99');
    expect(formatCurrency(1, 'USD')).toBe('$0.01');
    expect(formatCurrency(99, 'EUR')).toBe('€0.99');
    expect(formatCurrency(10050, 'GBP')).toBe('£100.50');
    expect(formatCurrency(333, 'USD')).toBe('$3.33');
  });

  test('should handle different currency formats', () => {
    expect(formatCurrency(5000, 'USD')).toBe('$50.00');
    expect(formatCurrency(5000, 'EUR')).toBe('€50.00');
    expect(formatCurrency(5000, 'GBP')).toBe('£50.00');
    expect(formatCurrency(5000, 'JPY')).toBe('¥50'); // JPY typically has no decimal places
  });

  // Bonus edge case tests
  test('should handle very small positive values', () => {
    expect(formatCurrency(1, 'USD')).toBe('$0.01');
    expect(formatCurrency(9, 'EUR')).toBe('€0.09');
  });

  test('should handle maximum safe integer values', () => {
    const maxSafeCents = Number.MAX_SAFE_INTEGER;
    expect(() => formatCurrency(maxSafeCents, 'USD')).not.toThrow();
    // Should produce a very large but valid currency string
    expect(formatCurrency(maxSafeCents, 'USD')).toMatch(/^\$\d+\.\d{2}$/);
  });
});
```

